"""Section solve result dataclasses."""

from __future__ import annotations

from dataclasses import dataclass
from typing import TYPE_CHECKING, Any, Optional

if TYPE_CHECKING:
    from fhecor_structuralcodes.geometry._plate import Plate


@dataclass
class SectionSolveResults:
    """
    Stores the results of a mixed-section solve from SectionModel.

    Args:
        strain: solved section strain plane (eps_a, chi_y, chi_z)
        forces_check: integrated resultants from solved strain (N, My, Mz)
        panel_plate_map: mapping panel index -> analyzed plates (mutated in-place)
        section_properties_snapshot: optional snapshot of gross section properties
    """

    strain: tuple[float, float, float]
    forces_check: tuple[float, float, float]
    panel_plate_map: dict[int, list["Plate"]]
    section_properties_snapshot: Optional[Any] = None
    class_based_constitutive_two_pass: bool = False


@dataclass
class EffectiveSectionIterationResults:
    """Stores results from iterative class 4 effective-geometry analysis."""

    strain: tuple[float, float, float]
    forces_check: tuple[float, float, float]
    effective_panel_plate_map: dict[int, list["Plate"]]
    convergence_history: list[float]
    iterations: int
    converged: bool
    section_properties_snapshot: Optional[Any] = None
    class_based_constitutive_two_pass: bool = False


@dataclass
class ULSBucklingSummaryEntry:
    """Buckling summary entry aggregated by original plate id."""

    origin_plate_id: int
    class_plate: Optional[int]
    rho: Optional[float]
    beff: Optional[float]
    be1: Optional[float]
    be2: Optional[float]
    plate_position: str
    num_effective_children: int
    k_sigma: Optional[float]
    lambda_p: Optional[float]  # Relative plate slenderness (Eq. 4.3)
    sigma_cr: Optional[float]  # Elastic critical plate buckling stress (MPa)

    def summary(self):
        """Returns a formatted string with the buckling summary."""

        def _fmt(v: Optional[float], fmt_str: str) -> str:
            return fmt_str.format(v) if v is not None else "N/A"

        return (
            f"--- ULS Buckling Summary Entry ---\n"
            f"Plate_ID: {self.origin_plate_id}\n"
            f"Class: {self.class_plate if self.class_plate is not None else 'N/A'}\n"
            f"rho: {_fmt(self.rho, '{:.2f}')}\n"
            f"beff: {_fmt(self.beff, '{:.2f}')} mm\n"
            f"be1: {_fmt(self.be1, '{:.2f}')} mm\n"
            f"be2: {_fmt(self.be2, '{:.2f}')} mm\n"
            f"Plate Position: {self.plate_position}\n"
            f"Number of Effective Children: {self.num_effective_children}\n"
            f"k_sigma: {_fmt(self.k_sigma, '{:.3f}')}\n"
            f"lambda_p: {_fmt(self.lambda_p, '{:.3f}')}\n"
            f"sigma_cr: {_fmt(self.sigma_cr, '{:.2f}')} MPa\n"
        )
